# Level 1: Extract token from header
def get_token(
    authorization: Annotated[str, Header()],
) -> str:
    if not authorization.startswith("Bearer "):
        raise HTTPException(status_code=401, detail="Invalid auth header")
    return authorization.removeprefix("Bearer ")

# Level 2: Decode token to user (depends on Level 1)
def get_current_user(
    token: Annotated[str, Depends(get_token)],
) -> dict:
    # In real code: decode JWT, query database
    if token == "valid-token":
        return {"id": 1, "name": "Alice", "is_admin": True}
    raise HTTPException(status_code=401, detail="Invalid token")

# Level 3: Require admin role (depends on Level 2)
def require_admin(
    user: Annotated[dict, Depends(get_current_user)],
) -> dict:
    if not user.get("is_admin"):
        raise HTTPException(status_code=403, detail="Admin required")
    return user

# Type aliases for clean handlers
CurrentUser = Annotated[dict, Depends(get_current_user)]
AdminUser = Annotated[dict, Depends(require_admin)]

